syntax = "proto3";

package test_app.v1;

import "google/protobuf/timestamp.proto";
import "google/protobuf/empty.proto";

option go_package = "github.com/your-org/test-app/gen/go/test_app/v1;test_appv1";
option java_multiple_files = true;
