  uint32 page_size = 2;
}

message ListPostResponse {
  repeated Post items = 1;
  uint32 total = 2;
  uint32 page = 3;
  uint32 page_size = 4;
}

message User {
  string id = 1; // pk, unique, required
  string name = 2; // required
  string email = 3; // unique, required
  bool active = 4; // required
  google.protobuf.Timestamp created_at = 5; // required
  google.protobuf.Timestamp created_at = 90;
  google.protobuf.Timestamp updated_at = 91;
}

message GetUserRequest {
  string id = 1;
}

message DeleteUserRequest {
  string id = 1;
}

message CreateUserRequest {
  string name = 1; // required
  string email = 2; // unique, required
  bool active = 3; // required
  google.protobuf.Timestamp created_at = 4; // required
}

message UpdateUserRequest {
  string id = 1;
  string name = 2; // required
  string email = 3; // unique, required
  bool active = 4; // required
  google.protobuf.Timestamp created_at = 5; // required
}

message ListUserRequest {
  uint32 page = 1;
  uint32 page_size = 2;
}

message ListUserResponse {
  repeated User items = 1;
  uint32 total = 2;
  uint32 page = 3;
  uint32 page_size = 4;
}

service PostService {
  rpc ListPost(ListPostRequest) returns (ListPostResponse);
  rpc GetPost(GetPostRequest) returns (Post);
  rpc CreatePost(CreatePostRequest) returns (Post);
  rpc UpdatePost(UpdatePostRequest) returns (Post);
  rpc DeletePost(DeletePostRequest) returns (google.protobuf.Empty);
}

service UserService {
  rpc ListUser(ListUserRequest) returns (ListUserResponse);
  rpc GetUser(GetUserRequest) returns (User);
  rpc CreateUser(CreateUserRequest) returns (User);
  rpc UpdateUser(UpdateUserRequest) returns (User);
  rpc DeleteUser(DeleteUserRequest) returns (google.protobuf.Empty);
}

